#include <queue>

using namespace std;

long long solve(std::vector<std::vector<long long>> grid, long long k) {
    int m = grid.size();
    if (m == 0) return 0;
    int n = grid[0].size();
    vector<vector<bool>> visited(m, vector<bool>(n, false));
    int count = 0;

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                queue<pair<int, int>> q;
                q.push({i, j});
                visited[i][j] = true;
                long long sum = 0;

                while (!q.empty()) {
                    auto current = q.front();
                    q.pop();
                    int x = current.first;
                    int y = current.second;
                    sum += grid[x][y];

                    // Check four directions
                    if (x > 0 && grid[x-1][y] > 0 && !visited[x-1][y]) {
                        visited[x-1][y] = true;
                        q.push({x-1, y});
                    }
                    if (x < m - 1 && grid[x+1][y] > 0 && !visited[x+1][y]) {
                        visited[x+1][y] = true;
                        q.push({x+1, y});
                    }
                    if (y > 0 && grid[x][y-1] > 0 && !visited[x][y-1]) {
                        visited[x][y-1] = true;
                        q.push({x, y-1});
                    }
                    if (y < n - 1 && grid[x][y+1] > 0 && !visited[x][y+1]) {
                        visited[x][y+1] = true;
                        q.push({x, y+1});
                    }
                }

                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }

    return count;
}

